function wsCount = WhitespaceCounter(userString)
    % Create a logical array where each element is true if the corresponding character is a whitespace character
    isWhitespace = isstrprop(userString, 'wspace');
    % Sum the number of true values in the logical array to get the count of whitespace characters
    wsCount = sum(isWhitespace);
end

function out = isPassCode(passCode)
    % Check if the passCode contains at least one lower case letter
    hasLower = any(isstrprop(passCode, 'lower'));
    % Check if the passCode contains at least one upper case letter
    hasUpper = any(isstrprop(passCode, 'upper'));
    % Check if the passCode contains at least one digit
    hasDigit = any(isstrprop(passCode, 'digit'));
    % Check if the passCode contains at least one punctuation character
    hasPunctuation = any(isstrprop(passCode, 'punct'));
    % Check if all the criteria are met and assign the appropriate logical value
    if hasLower && hasUpper && hasDigit && hasPunctuation
        out = true;
    else
        out = false;
    end
end

